select.if:
select a.*, m.site_id as site_id, m.category_id as category_id, s.name as site_name, c.name as category_name, c.icon as category_icon, -- 关联板块信息（通过分类的父级） CASE WHEN c.parent_id = 0 THEN c.id ELSE c.parent_id END as section_id, CASE WHEN c.parent_id = 0 THEN c.name ELSE (SELECT name FROM gb_categories WHERE id = c.parent_id AND del_flag = '0') END as section_name, sc.name as storage_config_name, sc.category_id as storage_category_id, scat.name as storage_category_name, CASE WHEN ahb.game_id IS NOT NULL THEN 'game' WHEN ahb.game_box_id IS NOT NULL THEN 'gamebox' ELSE NULL END as bind_type, COALESCE(ahb.game_id, ahb.game_box_id) as bind_target_id, -- 统一的可见性状态 CASE WHEN m.site_id = #{siteId} THEN a.status WHEN m.site_id = #{params.personalSiteId} THEN (CASE WHEN incl.id IS NOT NULL THEN incl.is_visible WHEN excl.id IS NULL THEN '1' ELSE '0' END) ELSE IFNULL(incl.is_visible, '0') END as is_visible, -- 关联来源标识 CASE WHEN m.site_id = #{siteId} THEN 'own' WHEN m.site_id = #{params.personalSiteId} THEN 'default' ELSE 'shared' END as relation_source, -- 是否被排除（仅对默认配置有效） CASE WHEN excl.id IS NOT NULL THEN '1' ELSE '0' END as is_excluded from gb_articles a inner join gb_master_articles m on a.master_article_id = m.id and m.del_flag = '0' left join gb_sites s on m.site_id = s.id and s.del_flag = '0' left join gb_categories c on m.category_id = c.id and c.del_flag = '0' left join gb_storage_configs sc on a.storage_config_id = sc.id and sc.del_flag = '0' left join gb_categories scat on sc.category_id = scat.id and scat.del_flag = '0' left join gb_master_article_homepage_binding ahb on a.master_article_id = ahb.master_article_id -- 左连接正向关联（include） LEFT JOIN gb_site_master_article_relations incl ON a.master_article_id = incl.master_article_id AND incl.site_id = #{siteId} AND incl.relation_type = 'include' -- 左连接排除关联（exclude） LEFT JOIN gb_site_master_article_relations excl ON a.master_article_id = excl.master_article_id AND excl.site_id = #{siteId} AND excl.relation_type = 'exclude'
a.del_flag = '0'
and a.master_article_id = #{masterArticleId}
AND ( m.site_id = #{siteId}
OR m.site_id = #{params.personalSiteId}
OR (m.site_id != #{siteId}
AND m.site_id != #{params.personalSiteId}
AND incl.id IS NOT NULL) )
and a.title like concat('%', #{title}, '%') and c.parent_id = #{sectionId} and m.category_id = #{categoryId} and a.locale = #{locale} and a.content_type = #{contentType} and a.author like concat('%', #{author}, '%') and m.is_top = #{isTop} and a.is_hot = #{isHot} and m.is_recommend = #{isRecommend}
AND ( (m.site_id = #{siteId} AND a.status = #{status}) OR (m.site_id = #{params.personalSiteId} AND ( CASE WHEN incl.id IS NOT NULL THEN incl.is_visible WHEN excl.id IS NULL THEN '1' ELSE '0' END ) = #{status}) OR (m.site_id != #{siteId} AND m.site_id != #{params.personalSiteId} AND IFNULL(incl.is_visible, '0') = #{status}) )
order by m.is_top desc, m.sort_order asc, a.create_time desc

select a.*, m.site_id as site_id, m.category_id as category_id, s.name as site_name, c.name as category_name, c.icon as category_icon, -- 关联板块信息（通过分类的父级） CASE WHEN c.parent_id = 0 THEN c.id ELSE c.parent_id END as section_id, CASE WHEN c.parent_id = 0 THEN c.name ELSE (SELECT name FROM gb_categories WHERE id = c.parent_id AND del_flag = '0') END as section_name, sc.name as storage_config_name, sc.category_id as storage_category_id, scat.name as storage_category_name, CASE WHEN ahb.game_id IS NOT NULL THEN 'game' WHEN ahb.game_box_id IS NOT NULL THEN 'gamebox' ELSE NULL END as bind_type, COALESCE(ahb.game_id, ahb.game_box_id) as bind_target_id from gb_articles a inner join gb_master_articles m on a.master_article_id = m.id and m.del_flag = '0' left join gb_sites s on m.site_id = s.id and s.del_flag = '0' left join gb_categories c on m.category_id = c.id and c.del_flag = '0' left join gb_storage_configs sc on a.storage_config_id = sc.id and sc.del_flag = '0' left join gb_categories scat on sc.category_id = scat.id and scat.del_flag = '0' left join gb_master_article_homepage_binding ahb on a.master_article_id = ahb.master_article_id
a.del_flag = '0'
and a.master_article_id = #{masterArticleId}
AND (m.site_id = #{siteId} OR m.site_id = #{params.personalSiteId})
AND m.site_id = #{siteId}
AND m.site_id = #{params.personalSiteId}
AND 1 = 0
and a.title like concat('%', #{title}, '%') and c.parent_id = #{sectionId} and m.category_id = #{categoryId} and a.locale = #{locale} and a.content_type = #{contentType} and a.author like concat('%', #{author}, '%') and m.is_top = #{isTop} and a.is_hot = #{isHot} and m.is_recommend = #{isRecommend} and a.status = #{status}
order by m.is_top desc, m.sort_order asc, a.create_time desc

mapper.update:
update gb_articles
slug = #{slug}, locale = #{locale}, title = #{title}, subtitle = #{subtitle}, tags = #{tags}, cover_url = #{coverUrl}, description = #{description}, content = #{content}, content_cleared_at = #{contentClearedAt}, content_auto_clear_days = #{contentAutoClearDays}, content_backup_key = #{contentBackupKey}, content_type = #{contentType}, generation_id = #{generationId}, author = #{author}, keywords = #{keywords}, view_count = #{viewCount}, like_count = #{likeCount}, favorite_count = #{favoriteCount}, comment_count = #{commentCount}, share_count = #{shareCount}, is_hot = #{isHot}, allow_comment = #{allowComment}, master_article_id = #{masterArticleId}, storage_config_id = #{storageConfigId}, storage_key = #{storageKey}, storage_url = #{storageUrl}, path_rule = #{pathRule}, seo_title = #{seoTitle}, seo_keywords = #{seoKeywords}, seo_description = #{seoDescription}, sort_order = #{sortOrder}, status = #{status}, update_by = #{updateBy}, update_time = #{updateTime}, publish_time = #{publishTime}, remote_file_status = #{remoteFileStatus}, last_sync_check_time = #{lastSyncCheckTime}, remote_file_size = #{remoteFileSize}, remote_file_hash = #{remoteFileHash},
where id = #{id}

mapper.select:
SELECT DISTINCT a.*, sar.is_visible as site_is_visible, sar.is_top as site_is_top, sar.is_recommend as site_is_recommend, sar.sort_order as site_sort_order FROM gb_articles a INNER JOIN gb_article_game_relations r ON a.id = r.article_id INNER JOIN gb_site_article_relations sar ON a.id = sar.article_id AND sar.site_id = #{siteId} INNER JOIN gb_master_articles m ON a.master_article_id = m.id AND m.del_flag = '0' WHERE r.game_id = #{gameId} AND a.status = '1' AND a.del_flag = '0' AND sar.is_visible = '1'
AND a.locale = #{locale}
ORDER BY sar.sort_order ASC, a.create_time DESC

SELECT DISTINCT a.*, sar.is_visible as site_is_visible, sar.is_top as site_is_top, sar.is_recommend as site_is_recommend, sar.sort_order as site_sort_order FROM gb_articles a INNER JOIN gb_article_box_relations r ON a.id = r.article_id INNER JOIN gb_site_article_relations sar ON a.id = sar.article_id AND sar.site_id = #{siteId} INNER JOIN gb_master_articles m ON a.master_article_id = m.id AND m.del_flag = '0' WHERE r.box_id = #{boxId} AND a.status = '1' AND a.del_flag = '0' AND sar.is_visible = '1'
AND a.locale = #{locale}
ORDER BY sar.sort_order ASC, a.create_time DESC

SELECT a.*
FROM gb_articles a
WHERE a.master_article_id = #{masterArticleId}
  AND a.locale = #{locale}
  AND a.del_flag = '0'
LIMIT 1
